// Union : l'une ou l'autre valeur
type Resultat = string | null;
type StatutCommande = 'en_attente' | 'expediee' | 'livree' | 'annulee';

function trouverUtilisateur(id: number): Resultat {
  // peut retourner un nom ou null si non trouvé
  return id === 1 ? 'Alice' : null;
}

// Intersection : cumule les deux types
type Nom = { prenom: string; nom: string };
type Contact = { email: string; telephone?: string };
type Personne = Nom & Contact;

const alice: Personne = {
  prenom: 'Alice',
  nom: 'Dupont',
  email: 'alice@exemple.fr'
};
